import { useEffect, useState } from "react";
import { getFantasmas } from "../backend/controllers/fantasmas";

const Body = () => {
  const [fantasmas, setFantasmas] = useState();

  useEffect(() => {
    getFantasmas().then((data) => setFantasmas(data));
  }, []);

  return (
    <div>
      <input />
      <table>
        <thead>
          <tr>
            <th>Imagen</th>
            <th>Título</th>
            <th>Autor</th>
            <th>Editorial</th>
            <th>Ejemplares</th>
            <th>Disponibles</th>
          </tr>
        </thead>
        <tbody>
          {fantasmas?.map((fantasma) => (
            <tr>
              <td>-</td>
              <td>Sistema</td>
              <td>Manetta</td>
              <td>Una</td>
              <td>1</td>
              <td>1</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Body;
